import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"月银魔铳-异火","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/月银魔铳-异火.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/月银魔铳-异火.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/月银魔铳-异火.md"};function _(p,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"月银魔铳-异火",tabindex:"-1"},[s("月银魔铳-异火 "),e("a",{class:"header-anchor",href:"#月银魔铳-异火","aria-label":'Permalink to "月银魔铳-异火"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),o('<h1 id="月银魔铳-异火-1" tabindex="-1">月银魔铳-异火 <a class="header-anchor" href="#月银魔铳-异火-1" aria-label="Permalink to &quot;月银魔铳-异火&quot;">​</a></h1><p>月银魔铳-异火<br> 本质：魔幻<br> 价格:  C+1500<br> 分类：步枪<br> 在噬日的余波中，萨满铁匠沙之圣者逃入了洪荒，并在其深处建立了一处宫殿锻造厂。他野蛮地抓捕妖邪，将它们丢入自己的炉中，用来铸成他的复仇武器。异火是这些武器中的最后一把，自他那被洪荒扭曲而成的工坊废墟中诞生。<br> 自圣者死后，异火和他的其他武器作品就散落在了尘世和洪荒各处，但罕有武器能与异火的恶名媲美。它的火焰燃烧着洪荒的力量，扭曲玷污而非吞噬任何被其触碰之物。在八目织者手中，异火夷平了无数领土，将战士化为无脸的怪物。</p><p>异火看起来是一把单发式的燧发步枪，体积4，力量需求4，武器伤害12L，但弹容量仅为：1；这意味着其不能应用使枪械具有【短点射】【长点射】【连射】的特性效果，其基础射程150米，它每次激发都将喷出喷出色彩斑斓的烟雾和火焰，具有特性：【癫火】,【熔毁诅咒】</p><p>癫火<br> 异火与持有者共同燃烧，异火的持有者在进入战斗后，眼中瞳孔就会变为燃烧着的明黄色，在射击时，除了需要子弹外，使用者还需要支付一点意志，之后明黄色的火焰将缠绕子弹，将弹头融化为无温无型的癫火，该次攻击获得1点额外的附加成功，被攻击命中的单位仅可以以【意志豁免】对抗本次攻击检定。</p><p>熔毁诅咒<br> 异火在造成伤害后，不会带走血肉或留下创口，而是将命中部位的血肉扭曲成骇人的形状，血肉化作珊瑚、手臂骨刺增生、脸部长满真菌等等。这些额外增生的部位不在算作被命中生物的一部分，而是增生物。在治疗时，这些增生的部位会随着敌人生命值的完好而逐渐脱落。而被异火所杀死的敌人，他的尸体将变成钙化物，珊瑚和真菌的融合体，想要简单的通过视觉、气味和声音来辨识受害者将是不可能的，需要进行一次难度等于异火使用者（决心属性数）的智力+生存：医治延长检定，才能确定受害者的身份，这个效果无法将受害者伪装成另一个人，视为C级创伤来源的诅咒【变形】效果。被此武器杀死的单位将无法以B级及以下的能力进行复活。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
